mapper.select:
       SELECT tptwd.*,
       	   tptw.inspection_item_nm
         FROM esg.tb_permit_to_work_detail tptwd
    LEFT JOIN esg.tb_dataset_safety_work_checklist_detail tptw
			ON tptw.inspection_item_id  = tptwd.inspection_item
        WHERE 1 = 1
          AND tptwd.write_year = #{writeYear}
          AND tptwd.doc_type = #{docType}
          AND tptwd.doc_no = #{docNo}
        ORDER BY tptwd.doc_seq,tptwd.ord_seq

